const raw = $input.first().json;
if (!raw.choices || !raw.choices[0]) throw new Error('[SPLIT] OpenAI gagal: ' + JSON.stringify(raw).substring(0, 200));
const content = raw.choices[0].message.content.trim();

// Buat pipeline_id dari tanggal
const now = new Date();
const dd   = String(now.getDate()).padStart(2,'0');
const mm   = String(now.getMonth()+1).padStart(2,'0');
const yyyy = now.getFullYear();
const pipeline_id = `video_${yyyy}${mm}${dd}`;

let script;
try {
  // Hapus markdown wrapper jika ada
  const cleaned = content
    .replace(/^```json\s*/i,'')
    .replace(/^```\s*/i,'')
    .replace(/\s*```$/i,'')
    .trim();
  script = JSON.parse(cleaned);
} catch(e) {
  console.warn('[SPLIT] JSON parse gagal, gunakan fallback');
  script = {
    topic: 'Fakta Seru Gajah Afrika yang Menakjubkan',
    genre: 'animals',
    hook: 'Gajah Afrika punya rahasia luar biasa!',
    scenes: [
      { scene_number:1, duration_sec:13, emotion:'excited',
        narration: 'Halo teman-teman! Tahukah kalian bahwa gajah Afrika adalah hewan darat terbesar di seluruh dunia? Gajah dewasa bisa memiliki berat hingga enam ton, seberat dua mobil truk besar! Sungguh menakjubkan bukan?',
        on_screen_text: 'GAJAH TERBESAR DI DUNIA!',
        visual_note: 'Gajah Afrika clay raksasa berwarna abu-abu berdiri gagah di savana, karakter wortel clay pakai topi safari berdiri di samping kaki gajah sambil menunjuk ke atas dengan ekspresi takjub, pohon akasia clay di latar belakang, langit biru cerah' },
      { scene_number:2, duration_sec:13, emotion:'wow',
        narration: 'Lihat telinga gajah yang sangat besar itu! Telinga gajah Afrika bisa selebar dua meter, hampir sebesar pintu rumah kita. Gajah menggunakan telinganya seperti kipas untuk mendinginkan tubuhnya di hari yang panas terik.',
