}

// Validasi dan normalisasi 10 scene
const TARGET = 10;
const rawScenes = script.scenes || [];
const scenes = rawScenes.slice(0, TARGET).map((s, idx) => ({
  scene_number:   s.scene_number  || idx + 1,
  duration_sec:   s.duration_sec  || 11,
  narration:      (s.narration    || `Scene ${idx+1}`).trim(),
  on_screen_text: (s.on_screen_text || 'FAKTA SERU!').toUpperCase().trim(),
  emotion:        s.emotion       || 'excited',
  visual_note:    s.visual_note   || s.narration || ''
}));

// Tambah scene jika kurang dari 10
while (scenes.length < TARGET) {
  const idx = scenes.length;
  scenes.push({
    scene_number:   idx + 1,
    duration_sec:   11,
    narration:      `Fakta seru ke-${idx+1} yang akan mengejutkan kamu!`,
    on_screen_text: 'FAKTA SERU!',
    emotion:        'excited',
    visual_note:    'Karakter wortel lucu melompat kegirangan'
