// Buat slug judul untuk nama folder (aman untuk filesystem)
function slugify(str) {
  return str
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g,'')
    .trim()
    .replace(/\s+/g,'_')
    .substring(0, 30);
}
const topicSlug     = slugify(script.topic || 'fakta_seru');
const folderName    = `${topicSlug}_${dd}_${mm}_${yyyy}`;
const totalDuration = scenes.reduce((s,c) => s + c.duration_sec, 0);

console.log(`[SPLIT] Topic: ${script.topic} | ${scenes.length} scenes | ~${totalDuration}s | Folder: ${folderName}`);

return { json: {
  pipeline_id,
  folder_name:      folderName,
  topic:            script.topic,
  genre:            script.genre || 'animals',
  hook:             script.hook  || '',
  hashtags:         script.hashtags || ['#shorts','#fyp'],
  total_duration:   totalDuration,
  total_scenes:     scenes.length,
  scenes,
  audio_filename:   `${pipeline_id}_narration.mp3`,
  video_filename:   `${pipeline_id}_final.mp4`
}};

