const { execSync } = require('child_process');
const fs   = require('fs');
const path = require('path');
const data = $input.first().json;

// ── KONFIGURASI ────────────────────────────────────────────
const LEONARDO_KEY = process.env.LEONARDO_API_KEY || '';
const BASE_DIR     = 'E:/tutorial_n8n/output';
const BUNDLE       = `${BASE_DIR}/${data.folder_name}`;
const IMG_DIR      = `${BUNDLE}/_tmp_images`;
fs.mkdirSync(IMG_DIR, { recursive: true });

// ── HELPER: Node HTTP request ───────────────────────────────
function httpPost(url, payload, headers) {
  const jsonPayload = JSON.stringify(payload).replace(/"/g, '\\"');
  const headerArgs  = Object.entries(headers).map(([k,v]) => `-H "${k}: ${v}"`).join(' ');
  const curlCmd     = `curl -s -X POST ${headerArgs} -d "${jsonPayload}" "${url}"`;
  try {
    const out = execSync(curlCmd, { encoding:'utf8', timeout:30000, shell:'cmd.exe' });
    return JSON.parse(out);
  } catch(e) {
    return { error: e.message };
  }
}

function httpGet(url, headers) {
  const headerArgs = Object.entries(headers).map(([k,v]) => `-H "${k}: ${v}"`).join(' ');
  const curlCmd    = `curl -s -X GET ${headerArgs} "${url}"`;
  try {
    const out = execSync(curlCmd, { encoding:'utf8', timeout:30000, shell:'cmd.exe' });
    return JSON.parse(out);
  } catch(e) {
    return { error: e.message };
  }
}

function downloadFile(url, destPath) {
  const cmd = `curl -s -L -o "${destPath}" "${url}"`;
  try {
    execSync(cmd, { timeout:60000, shell:'cmd.exe' });
    return fs.existsSync(destPath) && fs.statSync(destPath).size > 2000;
  } catch(e) { return false; }
}

// ── GENERATE GAMBAR PER SCENE ────────────────────────────────
// KUNCI: setiap scene punya prompt sendiri → gambar sesuai cerita
const CLAY_NEG = 'blurry, low quality, ugly, scary, violent, realistic photo, dark, horror, text, watermark, logo, adult content, nsfw, bad anatomy, deformed, extra limbs';

const scenes = data.scenes || [];
const scenesWithImages = [];

for (let i = 0; i < scenes.length; i++) {
  const scene = scenes[i];
  const imgPath = path.join(IMG_DIR, `scene${scene.scene_number}.jpg`).replace(/\\/g,'/');

  // Prompt per scene: gabung CLAY_STYLE + visual_note spesifik scene
  const visualDetail = (scene.visual_note || scene.narration || '').substring(0, 300);
  const scenePrompt  = [
    visualDetail + ',',
    'clay animation style, 3D render, cute chibi character,',
    'soft plasticine texture, bright cheerful colors, child-friendly kawaii style,',
    'smooth shiny clay surface, studio lighting, clean colorful background,',
    'portrait 9:16 vertical orientation, professional kids animation quality,',
    'vibrant color palette, no text, no watermark, no logo'
  ].join(' ');

  console.log(`[LEONARDO] Scene ${scene.scene_number}/${scenes.length}: ${visualDetail.substring(0,60)}...`);

  let imgUrl    = null;
  let imgOk     = false;
  let genError  = null;

  if (LEONARDO_KEY && LEONARDO_KEY.length > 10) {
    try {
      // Step 1: Request generate
      const genBody = {
        prompt:             scenePrompt.substring(0, 900),
        negative_prompt:    CLAY_NEG,
        modelId:            'b24e16ff-06e3-43eb-8d33-4416c2d75876',
        width:              576,
        height:             1024,
        num_images:         1,
        guidance_scale:     7,
        num_inference_steps: 25,
        public:             false,
        photoReal:          false,
        alchemy:            false
      };

      const genHeaders = {
        'Authorization': `Bearer ${LEONARDO_KEY}`,
        'Content-Type':  'application/json'
      };

      const genRes = httpPost('https://cloud.leonardo.ai/api/rest/v1/generations', genBody, genHeaders);

      if (genRes.sdGenerationJob && genRes.sdGenerationJob.generationId) {
        const genId = genRes.sdGenerationJob.generationId;
        console.log(`[LEONARDO] Scene ${scene.scene_number} genId: ${genId}`);

        // Step 2: Poll sampai selesai (max 60 detik)
        let pollAttempts = 0;
        while (pollAttempts < 12) {
          pollAttempts++;
          // Tunggu 5 detik
          execSync('ping -n 6 127.0.0.1 > nul', { timeout:10000, shell:'cmd.exe' });

          const pollRes = httpGet(
            `https://cloud.leonardo.ai/api/rest/v1/generations/${genId}`,
            genHeaders
          );

          const imgs = pollRes.generations_by_pk?.generated_images || [];
          if (imgs.length > 0 && imgs[0].url) {
            imgUrl = imgs[0].url;
            console.log(`[LEONARDO] Scene ${scene.scene_number} URL: ${imgUrl.substring(0,60)}...`);
            break;
          }
          console.log(`[LEONARDO] Scene ${scene.scene_number} poll ${pollAttempts}/12 menunggu...`);
        }
      } else {
        genError = JSON.stringify(genRes).substring(0, 150);
        console.warn(`[LEONARDO] Scene ${scene.scene_number} generate error:`, genError);
      }
    } catch(e) {
      genError = e.message.substring(0, 150);
      console.warn(`[LEONARDO] Scene ${scene.scene_number} exception:`, genError);
    }
  } else {
    console.warn('[LEONARDO] API key tidak ada, pakai picsum fallback');
  }

  // Download gambar
  if (imgUrl) {
    imgOk = downloadFile(imgUrl, imgPath);
    if (!imgOk) console.warn(`[LEONARDO] Scene ${scene.scene_number} download gagal, pakai fallback`);
  }

  // Fallback: picsum dengan seed unik per scene (gambar alam yang beragam)
  if (!imgOk) {
    const seed    = `${data.pipeline_id}_scene${scene.scene_number}_${scene.emotion}`;
    const fallUrl = `https://picsum.photos/seed/${encodeURIComponent(seed)}/576/1024`;
    imgOk = downloadFile(fallUrl, imgPath);
    if (imgOk) console.log(`[LEONARDO] Scene ${scene.scene_number} fallback picsum OK`);
    else console.error(`[LEONARDO] Scene ${scene.scene_number} SEMUA download gagal`);
  }

  scenesWithImages.push({
    ...scene,
    image_url:    imgOk ? imgPath : (imgUrl || ''),
    image_path:   imgPath,
    image_local:  imgOk,
    image_prompt: scene.image_prompt || '',
    gen_error:    genError
  });

  // Jeda antar scene untuk hindari rate limit Leonardo
  if (i < scenes.length - 1 && LEONARDO_KEY && LEONARDO_KEY.length > 10) {
    execSync('ping -n 4 127.0.0.1 > nul', { timeout:8000, shell:'cmd.exe' });
  }
}

const okCount = scenesWithImages.filter(s => s.image_local).length;
console.log(`[LEONARDO] Selesai: ${okCount}/${scenes.length} gambar berhasil`);

return { json: {
  ...data,
  scenes:       scenesWithImages,
  bundle_dir:   BUNDLE,
  images_dir:   IMG_DIR,
  images_ready: true,
  images_ok:    okCount
}};

