const { execSync } = require('child_process');
const fs   = require('fs');
const path = require('path');
const data = $input.first().json;

const FFMPEG    = 'C:/Users/User/AppData/Local/Microsoft/WinGet/Packages/Gyan.FFmpeg_Microsoft.Winget.Source_8wekyb3d8bbwe/ffmpeg-8.1-full_build/bin/ffmpeg.exe';
const FONT_BOLD = 'C\\:/Windows/Fonts/arialbd.ttf';
const FONT_NRM  = 'C\\:/Windows/Fonts/arial.ttf';

const BUNDLE  = data.bundle_dir;
const outPath = `${BUNDLE}/${data.video_filename}`;
fs.mkdirSync(BUNDLE, { recursive: true });

const scenes = data.scenes || [];

// ──────────────────────────────────────────────────────────
// STRATEGI SINKRONISASI:
// Setiap scene punya: 1 gambar + 1 audio → durasi = durasi audio
// FFmpeg: tiap scene dirender sendiri-sendiri lalu concat
// ──────────────────────────────────────────────────────────

function escTxt(t) {
  return (t || '')
    .replace(/\\/g,'\\\\')
    .replace(/'/g,"\\'")
    .replace(/:/g,'\\:')
    .replace(/[\[\]]/g,'')
    .replace(/,/g,' ')
    .replace(/"/g,'\\"')
    .replace(/\n/g,' ')
    .trim()
    .substring(0,55);
}

// Word wrap menjadi max 3 baris agar terbaca di layar HP
function wrapTxt(t, maxChar) {
  const words = t.split(' ');
  let line1 = '', line2 = '', line3 = '';
  for (const w of words) {
    if (!line1 || (line1 + ' ' + w).length <= maxChar) {
      line1 = (line1 ? line1 + ' ' : '') + w;
    } else if (!line2 || (line2 + ' ' + w).length <= maxChar) {
      line2 = (line2 ? line2 + ' ' : '') + w;
    } else if (!line3 || (line3 + ' ' + w).length <= maxChar) {
      line3 = (line3 ? line3 + ' ' : '') + w;
    }
    // sisa kata tidak ditampilkan (batasan layar)
  }
  // Pastikan setiap baris tidak terpotong di tengah kata
  return {
    line1: line1.trim().substring(0, maxChar),
    line2: line2.trim().substring(0, maxChar),
    line3: line3.trim().substring(0, maxChar)
  };
}

// ──────────────────────────────────────────────────────────
// Render setiap scene menjadi video clip sementara
// ──────────────────────────────────────────────────────────
const CLIP_DIR   = `${BUNDLE}/_tmp_clips`;
const clipPaths  = [];
fs.mkdirSync(CLIP_DIR, { recursive: true });

let totalRenderedSec = 0;
const renderErrors   = [];

for (let i = 0; i < scenes.length; i++) {
  const s       = scenes[i];
  const clipOut = path.join(CLIP_DIR, `clip${String(i+1).padStart(2,'0')}.mp4`).replace(/\\/g,'/');
  const imgSrc  = s.image_local ? s.image_path : (s.image_url || s.image_path);
  const audSrc  = s.audio_ok && s.audio_path && fs.existsSync(s.audio_path) ? s.audio_path : null;
  const durSec  = s.duration_sec || 10;

  // TEXT OVERLAY dari narasi yang diucapkan (SINKRON dengan audio)
  const narTxt      = escTxt(s.narration);
  const { line1, line2, line3 } = wrapTxt(narTxt, 28);
  const isHook      = i === 0;

  // Scene 1 (hook): judul besar di ATAS + narasi
  // Scene lain    : narasi di BAWAH 3 baris
  const hookTxt     = escTxt(data.hook || s.on_screen_text);

  // Layout teks
  const yBg   = isHook ? 40   : 780;
  const hBg   = isHook ? 200  : 240;
  const yL1   = isHook ? 58   : 794;
  const yL2   = isHook ? 130  : 858;
  const yL3   = isHook ? 182  : 918;
  const sz1   = isHook ? 42   : 32;
  const sz2   = isHook ? 32   : 29;
  const sz3   = isHook ? 26   : 27;
  const txt1  = isHook ? hookTxt : line1;
  const txt2  = isHook ? line1   : line2;
  const txt3  = isHook ? line2   : line3;

  // Nomor scene: pojok kanan atas
  const badgeTxt = `${i+1}/${scenes.length}`;

  // Filter drawtext per clip
  const filterBase = [
    `scale=576:1024:force_original_aspect_ratio=increase,crop=576:1024,setsar=1`,
    `drawbox=x=0:y=${yBg}:w=576:h=${hBg}:color=black@0.65:t=fill`,
    `drawtext=text='${txt1}':fontsize=${sz1}:fontcolor=white:borderw=3:bordercolor=black@0.8:x=(w-text_w)/2:y=${yL1}:fontfile='${FONT_BOLD}'`,
  ];

  // Tambah baris 2 jika ada isi
  if (txt2 && txt2.trim().length > 1) {
    filterBase.push(`drawtext=text='${txt2}':fontsize=${sz2}:fontcolor=#FFFACD:borderw=2:bordercolor=black@0.7:x=(w-text_w)/2:y=${yL2}:fontfile='${FONT_BOLD}'`);
  }

  // Tambah baris 3 jika ada isi (min 2 kata agar tidak tampil potongan kata)
  if (txt3 && txt3.trim().split(' ').length >= 2 && txt3.trim().length > 3) {
    filterBase.push(`drawtext=text='${txt3}':fontsize=${sz3}:fontcolor=#FFF8DC:borderw=2:bordercolor=black@0.7:x=(w-text_w)/2:y=${yL3}:fontfile='${FONT_NRM}'`);
  }

  // Badge nomor scene (pojok kanan atas)
  filterBase.push(`drawbox=x=w-68:y=8:w=60:h=34:color=black@0.6:t=fill`);
  filterBase.push(`drawtext=text='${badgeTxt}':fontsize=20:fontcolor=white:borderw=1:bordercolor=black:x=w-56:y=14:fontfile='${FONT_NRM}'`);

  const filterStr = filterBase.join(',');

  // Input: gambar + optional audio
  const inputImg  = `-loop 1 -t ${durSec} -i "${imgSrc}"`;
  const inputAud  = audSrc ? `-i "${audSrc}"` : '';
  const mapAud    = audSrc ? `-map 0:v -map 1:a -c:a aac -b:a 128k` : `-map 0:v -an`;
  const clipCmd   = `"${FFMPEG}" -y ${inputImg} ${inputAud} -vf "${filterStr}" ${mapAud} -c:v libx264 -preset fast -crf 26 -pix_fmt yuv420p -r 24 -shortest -movflags +faststart "${clipOut}"`;

  try {
    execSync(clipCmd, { stdio:'pipe', timeout:120000 });
    const clipOk = fs.existsSync(clipOut) && fs.statSync(clipOut).size > 1000;
    if (clipOk) {
      clipPaths.push(clipOut);
      totalRenderedSec += durSec;
      console.log(`[FFMPEG] Clip ${i+1}/${scenes.length}: ${durSec}s → OK (${Math.round(fs.statSync(clipOut).size/1024)}KB)`);
    } else {
      renderErrors.push(`Clip ${i+1}: file kosong`);
      console.warn(`[FFMPEG] Clip ${i+1}: file kosong`);
    }
  } catch(e) {
    const errMsg = e.message.substring(0,200);
    renderErrors.push(`Clip ${i+1}: ${errMsg}`);
    console.error(`[FFMPEG] Clip ${i+1} error:`, errMsg);
    // Simpan error untuk debugging
    try { fs.writeFileSync(`${BUNDLE}/render_error_scene${i+1}.txt`, e.message); } catch(ex) {}
  }
}

console.log(`[FFMPEG] ${clipPaths.length}/${scenes.length} clips berhasil, total ~${totalRenderedSec}s`);

// ──────────────────────────────────────────────────────────
// Concat semua clip menjadi 1 video final
// ──────────────────────────────────────────────────────────
let renderOk  = false;
let sizeMb    = 0;
let renderErr = null;

if (clipPaths.length === 0) {
  renderErr = 'Semua clip gagal dirender';
  console.error('[FFMPEG]', renderErr);
} else {
  // Tulis file list untuk concat
  const concatFile = path.join(CLIP_DIR, 'concat_list.txt').replace(/\\/g,'/');
  const listContent = clipPaths.map(p => `file '${p}'`).join('\n');
  fs.writeFileSync(concatFile, listContent, 'utf8');

  // Concat dengan re-encoding untuk stabilitas
  const concatCmd = `"${FFMPEG}" -y -f concat -safe 0 -i "${concatFile}" -c:v libx264 -preset fast -crf 24 -pix_fmt yuv420p -r 24 -c:a aac -b:a 128k -movflags +faststart "${outPath}"`;

  try {
    execSync(concatCmd, { stdio:'pipe', timeout:300000 });
    renderOk = fs.existsSync(outPath) && fs.statSync(outPath).size > 50000;
    sizeMb   = renderOk ? Math.round(fs.statSync(outPath).size / 1048576 * 100) / 100 : 0;
    console.log(`[FFMPEG] Final: ${renderOk ? 'SUKSES' : 'GAGAL'} - ${outPath} (${sizeMb} MB)`);
  } catch(e) {
    renderErr = e.message.substring(0,400);
    console.error('[FFMPEG] Concat error:', renderErr.substring(0,150));
    try { fs.writeFileSync(`${BUNDLE}/render_error_concat.txt`, renderErr); } catch(ex) {}
  }
}

return { json: {
